import { createApp } from 'vue'
import { createPinia } from 'pinia'
import router from './router'
import App from './App.vue'

// 主题系统 —— 必须在其他样式前加载（tokens 优先定义）
import './styles/theme-apple.css'
// 全局样式（Reset + Ant 组件覆盖）
import './style.css'
// Apple 风格细节增强（按钮/毛玻璃/滚动条/暗色组件补丁）
import './styles/apple-details.css'
// UI 增强样式（渐变按钮/卡片/菜单）—— 优先级最高
import './styles/ui-enhancements.css'
// 响应式
import './assets/responsive.css'

// 触发主题初始化（立即把 data-theme 设到 <html>，避免 FOUC）
import './composables/useTheme'

const app = createApp(App)
app.use(createPinia())
app.use(router)
app.mount('#app')

/**
 * WeCreator — 现代简约亮色主题
 * 
 * 设计规范：
 * - 纯白背景，现代简约风格
 * - 蓝色渐变主色调（按钮/高亮）
 * - 轻柔阴影 + 大圆角
 * - 高对比度文字（WCAG AA+）
 */

:root,
:root[data-theme="light"] {
  /* ==================== 背景色系 ==================== */
  --color-bg-page:        #FFFFFF;    /* 主背景：纯白 */
  --color-bg-container:   #FFFFFF;    /* 容器背景 */
  --color-bg-sidebar:     #FFFFFF;    /* 侧边栏：白色 */
  --color-bg-header:      #FFFFFF;    /* 顶栏：白色 */
  --color-bg-card:        #FFFFFF;    /* 卡片：白色 */
  --color-bg-card-2:      #FAFBFC;    /* 次级卡片 */
  --color-bg-hover:       #F5F7FA;    /* 悬停态：浅灰蓝 */
  --color-bg-active:      #EEF2F8;    /* 激活态：更浅蓝 */
  --color-bg-subtle:      #FAFBFC;    /* 弱化背景区 */
  --color-bg-elevated:    #FFFFFF;    /* 悬浮层（popover/tooltip） */
  --color-bg-mask:        rgba(0, 0, 0, 0.45);

  /* ==================== 主色渐变（按钮/高亮） ==================== */
  --color-primary:          #3D7EFF;    /* 主色纯色 */
  --color-primary-hover:    #2B6BE5;    /* 悬停 */
  --color-primary-active:   #1E5AD1;    /* 激活 */
  --color-primary-light:    #6B9FFF;    /* 浅色 */
  --color-primary-lighter:  #A3C4FF;    /* 更浅 */
  --color-primary-bg:       #E8EFFE;    /* 浅色背景 */
  --color-primary-bg-soft:  #F0F4FF;    /* 更浅背景 */
  --color-primary-border:   #C5D7FD;    /* 浅色边框 */

  /* 渐变定义 */
  --gradient-primary: linear-gradient(135deg, #4E8CFF 0%, #2B6BE5 100%);
  --gradient-primary-hover: linear-gradient(135deg, #5B97FF 0%, #3578EF 100%);

  /* ==================== 文字色系 ==================== */
  --color-text-primary:     #1D2939;    /* 主文字：深灰黑 */
  --color-text-secondary:   #475467;    /* 次文字：中灰 */
  --color-text-tertiary:    #667085;    /* 辅助文字 */
  --color-text-disabled:    #98A2B3;    /* 禁用 */
  --color-text-placeholder: #98A2B3;    /* 占位符 */
  --color-text-inverse:     #FFFFFF;    /* 反色（按钮上文字） */

  /* ==================== 边框 ==================== */
  --color-border:           #EAECF0;    /* 默认边框：浅灰 */
  --color-border-light:     #F2F4F7;    /* 更浅 */
  --color-border-strong:    #D0D5DD;    /* 较强 */
  --color-border-primary:   #4E8CFF;    /* 主色边框（focus） */

  /* ==================== 功能色 ==================== */
  --color-success:      #12B76A;
  --color-success-bg:   #ECFDF3;
  --color-success-border: #6CE9A6;
  --color-warning:      #F79009;
  --color-warning-bg:   #FFFAEB;
  --color-warning-border: #FEC84B;
  --color-error:        #F04438;
  --color-error-bg:     #FEF3F2;
  --color-error-border: #FDA29B;
  --color-info:         #4E8CFF;
  --color-info-bg:      #E8EFFE;
  --color-info-border:  #B2CCFF;

  /* 活力橙（辅助色） */
  --color-accent:       #FF9500;
  --color-accent-light: #FFB340;
  --color-accent-bg:    #FFF2E0;

  /* 青色（辅助色） */
  --color-teal:         #14B8A6;
  --color-teal-bg:      #E0F3F7;

  /* 紫色（辅助色） */
  --color-purple:       #9B51E0;
  --color-purple-bg:    #F3E5FA;

  /* ==================== 任务状态 ==================== */
  --status-draft-fg:      #667085;
  --status-draft-bg:      #F2F4F7;
  --status-matching-fg:   #3D7EFF;
  --status-matching-bg:   #E8EFFE;
  --status-progress-fg:   #14B8A6;
  --status-progress-bg:   #E0F3F7;
  --status-review-fg:     #F79009;
  --status-review-bg:     #FFFAEB;
  --status-completed-fg:  #12B76A;
  --status-completed-bg:  #ECFDF3;
  --status-closed-fg:     #98A2B3;
  --status-closed-bg:     #F9FAFB;

  /* ==================== 阴影（轻柔） ==================== */
  --shadow-xs: 0 1px 2px rgba(16, 24, 40, 0.05);
  --shadow-sm: 0 1px 3px rgba(16, 24, 40, 0.06), 0 1px 2px rgba(16, 24, 40, 0.04);
  --shadow-md: 0 4px 8px -2px rgba(16, 24, 40, 0.06), 0 2px 4px -2px rgba(16, 24, 40, 0.04);
  --shadow-lg: 0 12px 16px -4px rgba(16, 24, 40, 0.08), 0 4px 6px -2px rgba(16, 24, 40, 0.04);
  --shadow-xl: 0 20px 25px -5px rgba(16, 24, 40, 0.10), 0 10px 10px -5px rgba(16, 24, 40, 0.04);
  --shadow-focus: 0 0 0 4px rgba(78, 140, 255, 0.18);
  --shadow-focus-primary: 0 0 0 4px rgba(78, 140, 255, 0.18);

  /* ==================== 圆角 ==================== */
  --radius-xs: 4px;
  --radius-sm: 6px;
  --radius-md: 10px;
  --radius-lg: 14px;
  --radius-xl: 20px;

  /* ==================== 布局尺寸 ==================== */
  --layout-header-height: 56px;
  --layout-sider-width: 220px;
  --layout-sider-collapsed-width: 64px;

  /* ==================== 动画 ==================== */
  --duration-fast: 0.15s;
  --duration-normal: 0.25s;
  --duration-slow: 0.35s;
  --ease-in-out: cubic-bezier(0.4, 0, 0.2, 1);
  --ease-out: cubic-bezier(0.0, 0, 0.2, 1);
  --ease-in: cubic-bezier(0.4, 0, 1, 1);

  /* ==================== 毛玻璃效果（可选） ==================== */
  --vibrancy-filter: blur(20px) saturate(180%);
}

/* ==================== 暗色主题（已移除，保留占位避免报错） ==================== */
:root[data-theme="dark"] {
  /* 如果意外触发 dark，回退到 light */
  --color-bg-page: #FFFFFF;
  --color-text-primary: #1D2939;
}

/**
 * WeCreator — Apple Design Details
 * 在 theme-apple.css 变量基础上叠加 Apple 视觉细节
 */

/* ========== 全局过渡（主题切换平滑） ========== */
html,
body,
.ant-layout,
.ant-layout-sider,
.ant-layout-header,
.ant-card,
.ant-modal-content,
.ant-dropdown-menu,
.ant-popover-inner,
.ant-menu-item,
.ant-input,
.ant-select-selector,
.ant-btn {
  transition:
    background-color var(--duration-normal) var(--ease-out),
    border-color var(--duration-normal) var(--ease-out),
    color var(--duration-normal) var(--ease-out),
    box-shadow var(--duration-normal) var(--ease-out);
}

/* ========== 字体替换 ========== */
html,
body,
#app,
.ant-layout {
  font-family: var(--font-family-base) !important;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  text-rendering: optimizeLegibility;
  font-feature-settings: "kern" 1, "liga" 1, "calt" 1, "tnum" 1;
}

code,
pre,
.wc-mono {
  font-family: var(--font-family-mono);
}

/* ========== 毛玻璃材质 utility ========== */
.wc-vibrancy {
  background: var(--vibrancy-bg);
  backdrop-filter: var(--vibrancy-filter);
  -webkit-backdrop-filter: var(--vibrancy-filter);
}

.wc-vibrancy-strong {
  background: var(--vibrancy-bg);
  backdrop-filter: saturate(180%) blur(40px);
  -webkit-backdrop-filter: saturate(180%) blur(40px);
}

/* Header / Sidebar 默认应用毛玻璃 */
.ant-layout-header {
  backdrop-filter: var(--vibrancy-filter) !important;
  -webkit-backdrop-filter: var(--vibrancy-filter) !important;
}

.ant-layout-sider {
  backdrop-filter: var(--vibrancy-filter) !important;
  -webkit-backdrop-filter: var(--vibrancy-filter) !important;
}

/* ========== 按钮 Apple 式点击反馈 ========== */
.ant-btn:not(:disabled):active {
  transform: scale(0.97) !important;
  transition-duration: 80ms !important;
}

.ant-btn-primary:not(:disabled):hover {
  box-shadow: 0 4px 14px rgba(0, 122, 255, 0.32) !important;
  transform: translateY(-0.5px);
}

:root[data-theme="dark"] .ant-btn-primary:not(:disabled):hover {
  box-shadow: 0 4px 14px rgba(10, 132, 255, 0.40) !important;
}

/* 大圆角 pill 按钮变体 */
.ant-btn.wc-pill {
  border-radius: var(--radius-full) !important;
  padding-inline: 20px !important;
}

/* ========== 滚动条 Apple 细长款 ========== */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb {
  background: transparent;
  border-radius: var(--radius-full);
  border: 2px solid transparent;
  background-clip: padding-box;
  transition: background 150ms;
}
*:hover > ::-webkit-scrollbar-thumb,
::-webkit-scrollbar:hover::-webkit-scrollbar-thumb {
  background: rgba(60, 60, 67, 0.28);
  background-clip: padding-box;
}
::-webkit-scrollbar-thumb:hover {
  background: rgba(60, 60, 67, 0.50) !important;
  background-clip: padding-box;
}
:root[data-theme="dark"] ::-webkit-scrollbar-thumb {
  background: transparent;
}
:root[data-theme="dark"] *:hover > ::-webkit-scrollbar-thumb,
:root[data-theme="dark"] ::-webkit-scrollbar:hover::-webkit-scrollbar-thumb {
  background: rgba(235, 235, 245, 0.24);
  background-clip: padding-box;
}
:root[data-theme="dark"] ::-webkit-scrollbar-thumb:hover {
  background: rgba(235, 235, 245, 0.44) !important;
  background-clip: padding-box;
}

/* ========== 选中文本 ========== */
::selection {
  background: var(--color-primary-bg);
  color: var(--color-primary);
}

/* ========== 菜单项 Apple 软圆角 + 微缩 ========== */
.ant-menu-item {
  border-radius: var(--radius-md) !important;
  margin-inline: 8px !important;
  width: calc(100% - 16px) !important;
}

.ant-menu-item:active {
  transform: scale(0.98);
}

/* ========== 卡片大圆角 ========== */
.ant-card {
  border-radius: var(--radius-lg) !important;
}

.ant-modal-content {
  border-radius: var(--radius-xl) !important;
}

.ant-dropdown-menu,
.ant-popover-inner {
  border-radius: var(--radius-lg) !important;
  box-shadow: var(--shadow-lg) !important;
  background: var(--color-bg-elevated) !important;
  border: 0.5px solid var(--color-border-light) !important;
}

.ant-tooltip-inner {
  border-radius: var(--radius-md) !important;
  backdrop-filter: var(--vibrancy-filter);
  -webkit-backdrop-filter: var(--vibrancy-filter);
}

/* ========== 输入类 Apple 圆角 ========== */
.ant-input,
.ant-input-affix-wrapper,
.ant-select-selector,
.ant-input-number,
.ant-picker {
  border-radius: var(--radius-md) !important;
}

.ant-input:focus,
.ant-input-affix-wrapper-focused,
.ant-select-focused .ant-select-selector,
.ant-picker-focused {
  box-shadow: var(--shadow-focus-primary) !important;
}

/* ========== 暗色下表格/卡片背景适配 ========== */
:root[data-theme="dark"] .ant-layout {
  background: var(--color-bg-page) !important;
}
:root[data-theme="dark"] .ant-layout-content {
  background: var(--color-bg-page) !important;
}
:root[data-theme="dark"] .ant-card,
:root[data-theme="dark"] .ant-modal-content,
:root[data-theme="dark"] .ant-drawer-content,
:root[data-theme="dark"] .ant-notification-notice,
:root[data-theme="dark"] .ant-message-notice-content {
  background: var(--color-bg-card) !important;
}

:root[data-theme="dark"] .ant-table {
  background: transparent !important;
  color: var(--color-text-primary) !important;
}
:root[data-theme="dark"] .ant-table-thead > tr > th {
  background: var(--color-bg-card-2) !important;
  color: var(--color-text-secondary) !important;
  border-bottom-color: var(--color-border-light) !important;
}
:root[data-theme="dark"] .ant-table-tbody > tr > td {
  background: var(--color-bg-card) !important;
  color: var(--color-text-primary) !important;
  border-bottom-color: var(--color-border-light) !important;
}
:root[data-theme="dark"] .ant-table-tbody > tr:hover > td {
  background: var(--color-bg-hover) !important;
}
:root[data-theme="dark"] .ant-table-placeholder > td {
  background: var(--color-bg-card) !important;
}

:root[data-theme="dark"] .ant-input,
:root[data-theme="dark"] .ant-input-affix-wrapper,
:root[data-theme="dark"] .ant-input-number,
:root[data-theme="dark"] .ant-select-selector,
:root[data-theme="dark"] .ant-picker {
  background: var(--color-bg-card-2) !important;
  border-color: var(--color-border) !important;
  color: var(--color-text-primary) !important;
}
:root[data-theme="dark"] .ant-input::placeholder,
:root[data-theme="dark"] .ant-input-number-input::placeholder {
  color: var(--color-text-placeholder) !important;
}
:root[data-theme="dark"] .ant-select-selection-placeholder {
  color: var(--color-text-placeholder) !important;
}
:root[data-theme="dark"] .ant-select-arrow,
:root[data-theme="dark"] .ant-picker-suffix {
  color: var(--color-text-tertiary) !important;
}

:root[data-theme="dark"] .ant-btn-default {
  background: var(--color-bg-card-2) !important;
  border-color: var(--color-border) !important;
  color: var(--color-text-primary) !important;
}
:root[data-theme="dark"] .ant-btn-default:hover {
  background: var(--color-bg-hover) !important;
  border-color: var(--color-primary-border) !important;
  color: var(--color-primary) !important;
}

:root[data-theme="dark"] .ant-tabs-tab {
  color: var(--color-text-secondary) !important;
}
:root[data-theme="dark"] .ant-tabs > .ant-tabs-nav::before {
  border-bottom-color: var(--color-border-light) !important;
}

:root[data-theme="dark"] .ant-divider {
  border-color: var(--color-border-light) !important;
}

:root[data-theme="dark"] .ant-empty-description {
  color: var(--color-text-tertiary) !important;
}

:root[data-theme="dark"] .ant-pagination-item {
  background: transparent !important;
  border-color: var(--color-border) !important;
}
:root[data-theme="dark"] .ant-pagination-item a {
  color: var(--color-text-secondary) !important;
}

:root[data-theme="dark"] .ant-dropdown-menu-item {
  color: var(--color-text-secondary) !important;
}
:root[data-theme="dark"] .ant-dropdown-menu-item:hover {
  background: var(--color-bg-hover) !important;
  color: var(--color-text-primary) !important;
}

:root[data-theme="dark"] .ant-tooltip-inner {
  background: rgba(44, 44, 46, 0.92) !important;
  color: var(--color-text-primary) !important;
}

:root[data-theme="dark"] .ant-modal-title,
:root[data-theme="dark"] .ant-drawer-title {
  color: var(--color-text-primary) !important;
}

:root[data-theme="dark"] .ant-modal-close-x {
  color: var(--color-text-tertiary) !important;
}

:root[data-theme="dark"] .ant-modal-header,
:root[data-theme="dark"] .ant-modal-footer,
:root[data-theme="dark"] .ant-drawer-header {
  background: transparent !important;
  border-color: var(--color-border-light) !important;
}

:root[data-theme="dark"] .ant-steps-item-title,
:root[data-theme="dark"] .ant-steps-item-description {
  color: var(--color-text-secondary) !important;
}

/* ========== 主题切换器组件样式 ========== */
.wc-theme-switcher {
  display: inline-flex;
  align-items: center;
  background: var(--color-bg-card-2);
  border-radius: var(--radius-full);
  padding: 3px;
  gap: 2px;
}
.wc-theme-switcher .seg {
  width: 28px;
  height: 24px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: var(--radius-full);
  font-size: 12px;
  color: var(--color-text-secondary);
  cursor: pointer;
  user-select: none;
  transition: all var(--duration-fast) var(--ease-out);
  background: transparent;
  border: none;
  padding: 0;
  line-height: 1;
}
.wc-theme-switcher .seg:hover {
  color: var(--color-text-primary);
}
.wc-theme-switcher .seg.active {
  background: var(--color-bg-card);
  color: var(--color-primary);
  box-shadow: var(--shadow-sm);
}
.wc-theme-switcher .seg:active {
  transform: scale(0.92);
}

/* ========== 段落 / 标题 Apple 字重和字距 ========== */
h1, h2, h3, h4, h5, h6,
.ant-typography h1, .ant-typography h2, .ant-typography h3, .ant-typography h4 {
  letter-spacing: -0.02em;
  font-feature-settings: "ss01" 1;
}

.wc-display { font-size: 40px; font-weight: 700; letter-spacing: -0.03em; line-height: 1.1; }
.wc-title   { font-size: 24px; font-weight: 600; letter-spacing: -0.02em; line-height: 1.2; }

/* ========== Badge / Tag 大圆角 ========== */
.ant-tag {
  border-radius: var(--radius-sm) !important;
  padding-inline: 10px !important;
  font-weight: 500 !important;
}

/* ========== 禁用 ant layout 默认阴影以便我们自己控制 ========== */
.ant-layout-sider {
  box-shadow: none !important;
  border-right: 0.5px solid var(--color-border-light) !important;
}
.ant-layout-header {
  box-shadow: none !important;
  border-bottom: 0.5px solid var(--color-border-light) !important;
}

/* ==========================================================
   Apple HIG 按钮规范 —— 全面重写
   五大变体：Filled 主操作 / Tinted 次操作 / Gray 弱操作 / Plain 纯文字 / Destructive 危险
   参考：https://developer.apple.com/design/human-interface-guidelines/buttons
   ========================================================== */

/* 基础：高度、圆角、字重、动效 */
.ant-btn {
  font-weight: 500 !important;
  letter-spacing: -0.01em !important;
  border-radius: var(--radius-md) !important;
  transition:
    background var(--duration-fast) var(--ease-out),
    border-color var(--duration-fast) var(--ease-out),
    color var(--duration-fast) var(--ease-out),
    box-shadow var(--duration-fast) var(--ease-out),
    transform 80ms var(--ease-out) !important;
  display: inline-flex !important;
  align-items: center !important;
  justify-content: center !important;
  gap: 6px !important;
}

.ant-btn:not(:disabled):active {
  transform: scale(0.97) !important;
}

/* ---------- Filled / Primary（主操作） ---------- */
.ant-btn-primary {
  background: var(--color-primary) !important;
  border-color: var(--color-primary) !important;
  color: #FFFFFF !important;
  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.06), 0 0 0 0.5px rgba(0, 0, 0, 0.04) !important;
}
.ant-btn-primary > span,
.ant-btn-primary > .anticon {
  color: #FFFFFF !important;
}
.ant-btn-primary:not(:disabled):hover {
  background: var(--color-primary-hover) !important;
  border-color: var(--color-primary-hover) !important;
  color: #FFFFFF !important;
  box-shadow: 0 4px 14px rgba(0, 122, 255, 0.32) !important;
  transform: translateY(-0.5px);
}
.ant-btn-primary:not(:disabled):active {
  background: var(--color-primary-active) !important;
  border-color: var(--color-primary-active) !important;
  color: #FFFFFF !important;
  transform: scale(0.97) !important;
  box-shadow: none !important;
}

:root[data-theme="dark"] .ant-btn-primary:not(:disabled):hover {
  box-shadow: 0 4px 14px rgba(10, 132, 255, 0.44) !important;
}

/* ---------- Default（线框 / Gray） ---------- */
.ant-btn-default {
  background: var(--color-bg-card) !important;
  border-color: var(--color-border) !important;
  color: var(--color-text-primary) !important;
  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.04) !important;
}
.ant-btn-default > span,
.ant-btn-default > .anticon {
  color: inherit !important;
}
.ant-btn-default:not(:disabled):hover {
  background: var(--color-bg-hover) !important;
  border-color: var(--color-primary-border) !important;
  color: var(--color-primary) !important;
}
.ant-btn-default:not(:disabled):hover > span,
.ant-btn-default:not(:disabled):hover > .anticon {
  color: var(--color-primary) !important;
}
.ant-btn-default:not(:disabled):active {
  background: var(--color-primary-bg-soft) !important;
  border-color: var(--color-primary) !important;
  color: var(--color-primary-active) !important;
}

:root[data-theme="dark"] .ant-btn-default {
  background: var(--color-bg-card-2) !important;
  border-color: var(--color-border) !important;
  color: var(--color-text-primary) !important;
}
:root[data-theme="dark"] .ant-btn-default:not(:disabled):hover {
  background: rgba(10, 132, 255, 0.16) !important;
  border-color: var(--color-primary) !important;
  color: var(--color-primary) !important;
}

/* ---------- Text（纯文字） ---------- */
.ant-btn-text {
  background: transparent !important;
  border-color: transparent !important;
  box-shadow: none !important;
  color: var(--color-text-primary) !important;
}
.ant-btn-text > span,
.ant-btn-text > .anticon {
  color: inherit !important;
}
.ant-btn-text:not(:disabled):hover {
  background: var(--color-bg-hover) !important;
  color: var(--color-text-primary) !important;
}
.ant-btn-text:not(:disabled):active {
  background: var(--color-primary-bg-soft) !important;
}

/* ---------- Link（链接） ---------- */
.ant-btn-link {
  background: transparent !important;
  border-color: transparent !important;
  box-shadow: none !important;
  color: var(--color-primary) !important;
  padding-inline: 4px !important;
  font-weight: 400 !important;
}
.ant-btn-link > span,
.ant-btn-link > .anticon {
  color: inherit !important;
}
.ant-btn-link:not(:disabled):hover {
  background: transparent !important;
  color: var(--color-primary-hover) !important;
  text-decoration: none !important;
}
.ant-btn-link:not(:disabled):active {
  color: var(--color-primary-active) !important;
}

/* ---------- Dashed ---------- */
.ant-btn-dashed {
  background: transparent !important;
  border-color: var(--color-border) !important;
  border-style: dashed !important;
  color: var(--color-text-secondary) !important;
}
.ant-btn-dashed:not(:disabled):hover {
  border-color: var(--color-primary-border) !important;
  color: var(--color-primary) !important;
  background: var(--color-primary-bg-soft) !important;
}

/* ---------- Dangerous 危险 ---------- */
/* Primary Danger：红底白字 */
.ant-btn-dangerous.ant-btn-primary {
  background: var(--color-error) !important;
  border-color: var(--color-error) !important;
  color: #FFFFFF !important;
}
.ant-btn-dangerous.ant-btn-primary > span,
.ant-btn-dangerous.ant-btn-primary > .anticon {
  color: #FFFFFF !important;
}
.ant-btn-dangerous.ant-btn-primary:not(:disabled):hover {
  background: #FF6159 !important;
  border-color: #FF6159 !important;
  color: #FFFFFF !important;
  box-shadow: 0 4px 14px rgba(255, 59, 48, 0.36) !important;
}

/* Default Danger：红框红字 */
.ant-btn-dangerous:not(.ant-btn-primary):not(.ant-btn-link):not(.ant-btn-text) {
  background: var(--color-bg-card) !important;
  border-color: var(--color-error) !important;
  color: var(--color-error) !important;
}
.ant-btn-dangerous:not(.ant-btn-primary):not(.ant-btn-link):not(.ant-btn-text):hover {
  background: var(--color-error-bg) !important;
  border-color: var(--color-error) !important;
  color: var(--color-error) !important;
}
:root[data-theme="dark"] .ant-btn-dangerous:not(.ant-btn-primary):not(.ant-btn-link):not(.ant-btn-text) {
  background: var(--color-bg-card-2) !important;
}

/* Link Danger */
.ant-btn-dangerous.ant-btn-link {
  color: var(--color-error) !important;
}
.ant-btn-dangerous.ant-btn-link:hover {
  color: #FF6159 !important;
}

/* Text Danger */
.ant-btn-dangerous.ant-btn-text {
  color: var(--color-error) !important;
}
.ant-btn-dangerous.ant-btn-text:hover {
  background: var(--color-error-bg) !important;
  color: var(--color-error) !important;
}

/* ---------- 尺寸 ---------- */
.ant-btn-lg {
  height: 44px !important;
  font-size: 12px !important;
  font-weight: 600 !important;
  letter-spacing: 0.01em !important;
  border-radius: var(--radius-lg) !important;
  padding-inline: 20px !important;
}

.ant-btn-sm {
  height: 28px !important;
  font-size: 12px !important;
  padding-inline: 12px !important;
  border-radius: var(--radius-sm) !important;
}

/* ---------- Disabled（统一样式） ---------- */
.ant-btn:disabled,
.ant-btn[disabled],
.ant-btn:disabled:hover,
.ant-btn[disabled]:hover {
  opacity: 0.40 !important;
  cursor: not-allowed !important;
  pointer-events: auto !important;
  transform: none !important;
  box-shadow: none !important;
}
.ant-btn-primary:disabled,
.ant-btn-primary[disabled] {
  background: var(--color-primary) !important;
  border-color: var(--color-primary) !important;
  color: #FFFFFF !important;
}

/* ---------- 图标间距 ---------- */
.ant-btn > .anticon + span,
.ant-btn > span + .anticon {
  margin-inline-start: 0 !important;
}

/* ---------- Loading 图标跟随字色 ---------- */
.ant-btn-primary .ant-btn-loading-icon {
  color: #FFFFFF !important;
}
.ant-btn-default .ant-btn-loading-icon {
  color: var(--color-primary) !important;
}

/* ---------- Popconfirm / 表格内小按钮修正 ---------- */
.ant-popconfirm-buttons .ant-btn {
  font-size: 12px !important;
}

/* ---------- 表单 Action Row ---------- */
.ant-form-item .ant-btn {
  min-width: 72px;
}

/**
 * WeCreator — UI 增强样式
 * 
 * 在 Ant Design Vue tokens 基础上追加：
 * - 主按钮蓝色渐变
 * - 卡片/菜单微交互
 * - 登录页样式统一
 * 
 * 参照 uipic.png 的现代简约风格
 */

/* ==================== 全局基础 ==================== */
html, body, #app {
  background: #FFFFFF;
  color: #1D2939;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'SF Pro Text', 'SF Pro Display',
    'Helvetica Neue', 'PingFang SC', 'Hiragino Sans GB', 'Microsoft YaHei', sans-serif;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* ==================== 主按钮：蓝色渐变 ==================== */
.ant-btn-primary:not(.ant-btn-dangerous):not(:disabled):not(.ant-btn-background-ghost):not(.ant-btn-link) {
  background: linear-gradient(135deg, #4E8CFF 0%, #2B6BE5 100%) !important;
  border: none !important;
  box-shadow: 0 2px 4px rgba(43, 107, 229, 0.20);
  transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
}

.ant-btn-primary:not(.ant-btn-dangerous):not(:disabled):not(.ant-btn-background-ghost):not(.ant-btn-link):hover {
  background: linear-gradient(135deg, #5B97FF 0%, #3578EF 100%) !important;
  box-shadow: 0 4px 12px rgba(43, 107, 229, 0.28);
  transform: translateY(-1px);
}

.ant-btn-primary:not(.ant-btn-dangerous):not(:disabled):not(.ant-btn-background-ghost):not(.ant-btn-link):active {
  background: linear-gradient(135deg, #3D7EFF 0%, #1E5AD1 100%) !important;
  box-shadow: 0 1px 2px rgba(43, 107, 229, 0.24);
  transform: translateY(0);
}

.ant-btn-primary:disabled,
.ant-btn-primary[disabled] {
  background: #F2F4F7 !important;
  color: #98A2B3 !important;
  box-shadow: none !important;
}

/* 次按钮（default）悬停柔和 */
.ant-btn-default:not(:disabled):hover {
  border-color: #C5D7FD !important;
  color: #3D7EFF !important;
  background: #F5F7FA !important;
}

/* 大号按钮 */
.ant-btn-lg {
  font-weight: 500;
  letter-spacing: 0.02em;
}

/* ==================== 卡片 ==================== */
.ant-card {
  border: 1px solid #EAECF0 !important;
  box-shadow: 0 1px 2px rgba(16, 24, 40, 0.04) !important;
  transition: box-shadow 0.2s ease, transform 0.2s ease;
}

.ant-card-hoverable:hover {
  box-shadow: 0 12px 16px -4px rgba(16, 24, 40, 0.08), 0 4px 6px -2px rgba(16, 24, 40, 0.04) !important;
  transform: translateY(-2px);
}

.ant-card-head {
  border-bottom: 1px solid #F2F4F7 !important;
  min-height: 52px;
}

.ant-card-head-title {
  font-size: 12px;
  font-weight: 600;
  color: #1D2939;
}

/* ==================== 菜单现代化 ==================== */
.ant-menu-light.ant-menu-inline,
.ant-menu-light.ant-menu-vertical {
  background: transparent !important;
  border-inline-end: none !important;
}

.ant-menu-light .ant-menu-item {
  color: #475467;
  font-weight: 500;
}

.ant-menu-light .ant-menu-item-selected {
  background: #EEF2F8 !important;
  color: #2B6BE5 !important;
  font-weight: 600;
}

.ant-menu-light .ant-menu-item-selected::after {
  display: none !important;
}

.ant-menu-light .ant-menu-item:hover,
.ant-menu-light .ant-menu-submenu-title:hover {
  color: #1D2939 !important;
  background: #F5F7FA !important;
}

.ant-menu-light .ant-menu-submenu-selected > .ant-menu-submenu-title {
  color: #2B6BE5 !important;
}

/* 子菜单项缩进优化 */
.ant-menu-light .ant-menu-sub.ant-menu-inline {
  background: transparent !important;
}

/* ==================== 输入框 ==================== */
.ant-input,
.ant-input-affix-wrapper,
.ant-select .ant-select-selector,
.ant-picker,
.ant-input-number,
.ant-input-password {
  background: #FFFFFF !important;
  border-color: #EAECF0 !important;
  color: #1D2939 !important;
  transition: all 0.2s ease;
}

.ant-input:hover,
.ant-input-affix-wrapper:hover,
.ant-select:not(.ant-select-disabled):hover .ant-select-selector,
.ant-picker:hover {
  border-color: #C5D7FD !important;
}

.ant-input:focus,
.ant-input-affix-wrapper-focused,
.ant-select-focused .ant-select-selector,
.ant-picker-focused {
  border-color: #3D7EFF !important;
  box-shadow: 0 0 0 4px rgba(78, 140, 255, 0.18) !important;
}

/* ==================== 表格 ==================== */
.ant-table {
  border-radius: 12px !important;
  overflow: hidden;
}

.ant-table-thead > tr > th {
  background: #FAFBFC !important;
  color: #475467 !important;
  font-weight: 600 !important;
  border-bottom: 1px solid #EAECF0 !important;
  font-size: 12px;
}

.ant-table-tbody > tr > td {
  border-bottom: 1px solid #F2F4F7 !important;
  color: #1D2939;
}

.ant-table-tbody > tr:hover > td {
  background: #FAFBFC !important;
}

/* ==================== 标签/Tag ==================== */
.ant-tag {
  border-radius: 6px;
  font-weight: 500;
  border: none;
  padding: 2px 8px;
}

/* ==================== Modal ==================== */
.ant-modal-content {
  border-radius: 16px !important;
  box-shadow: 0 20px 25px -5px rgba(16, 24, 40, 0.10), 0 10px 10px -5px rgba(16, 24, 40, 0.04) !important;
}

.ant-modal-header {
  border-bottom: 1px solid #F2F4F7 !important;
}

.ant-modal-title {
  font-size: 14px !important;
  font-weight: 600 !important;
  color: #1D2939 !important;
}

/* ==================== Dropdown ==================== */
.ant-dropdown-menu {
  border-radius: 10px !important;
  padding: 6px !important;
  box-shadow: 0 12px 16px -4px rgba(16, 24, 40, 0.08), 0 4px 6px -2px rgba(16, 24, 40, 0.04) !important;
  border: 1px solid #F2F4F7;
}

.ant-dropdown-menu-item {
  border-radius: 6px !important;
  padding: 8px 12px !important;
  margin: 1px 0;
}

.ant-dropdown-menu-item:hover {
  background: #F5F7FA !important;
}

/* ==================== 滚动条（现代化） ==================== */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: #EAECF0;
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: #D0D5DD;
}

/* ==================== 登录/注册页（强制亮色 + 渐变背景） ==================== */
.auth-layout,
.login-page,
.register-page,
.auth-bg,
body.auth-body {
  background: linear-gradient(135deg, #F0F4FF 0%, #FFFFFF 50%, #E8EFFE 100%) !important;
  min-height: 100vh;
}

.auth-card,
.login-card,
.register-card {
  background: #FFFFFF !important;
  border-radius: 20px !important;
  box-shadow: 0 20px 40px -8px rgba(16, 24, 40, 0.12), 0 8px 16px -4px rgba(16, 24, 40, 0.06) !important;
  border: 1px solid #F2F4F7 !important;
}

/* ==================== Tabs ==================== */
.ant-tabs-tab {
  font-weight: 500 !important;
}

.ant-tabs-tab-active .ant-tabs-tab-btn {
  color: #3D7EFF !important;
  font-weight: 600 !important;
}

.ant-tabs-ink-bar {
  background: linear-gradient(90deg, #4E8CFF 0%, #2B6BE5 100%) !important;
  height: 3px !important;
}

/* ==================== 分页 ==================== */
.ant-pagination-item-active {
  background: linear-gradient(135deg, #4E8CFF 0%, #2B6BE5 100%) !important;
  border-color: transparent !important;
}

.ant-pagination-item-active a {
  color: #FFFFFF !important;
}

/* ==================== Steps ==================== */
.ant-steps-item-finish .ant-steps-item-icon {
  background: linear-gradient(135deg, #4E8CFF 0%, #2B6BE5 100%) !important;
  border-color: transparent !important;
}

.ant-steps-item-finish .ant-steps-item-icon > .ant-steps-icon {
  color: #FFFFFF !important;
}

.ant-steps-item-process .ant-steps-item-icon {
  background: linear-gradient(135deg, #4E8CFF 0%, #2B6BE5 100%) !important;
  border-color: transparent !important;
}

/* ==================== Switch ==================== */
.ant-switch-checked {
  background: linear-gradient(135deg, #4E8CFF 0%, #2B6BE5 100%) !important;
}

/* ==================== Progress ==================== */
.ant-progress-bg {
  background: linear-gradient(90deg, #4E8CFF 0%, #2B6BE5 100%) !important;
}

/* ==================== 去除毛玻璃效果（亮色下不需要） ==================== */
.wc-vibrancy,
.ant-layout-header[style*="backdrop-filter"] {
  backdrop-filter: none !important;
  -webkit-backdrop-filter: none !important;
}

/* ==================== 修复暗色残留 ==================== */
[data-theme="dark"] {
  /* 强制覆盖任何可能的 dark 主题样式 */
  background: #FFFFFF !important;
  color: #1D2939 !important;
}

