}

.md-tertiary {
  background: var(--md-sys-color-tertiary) !important;
  color: var(--md-sys-color-on-tertiary) !important;
}

.md-error {
  background: var(--md-sys-color-error) !important;
  color: var(--md-sys-color-on-error) !important;
}

/* Elevation utilities */
.md-elevation-0 { box-shadow: var(--md-sys-elevation-0) !important; }
.md-elevation-1 { box-shadow: var(--md-sys-elevation-1) !important; }
