 * WeCreator — Material Design 3 全局覆盖
 * 
 * 替代原 ui-enhancements.css + apple-details.css
 * 覆盖 Ant Design Vue 组件以符合 M3 规范
 */

/* ==================== 全局过渡 ==================== */
html, body, .ant-layout, .ant-layout-sider, .ant-layout-header,
.ant-card, .ant-modal-content, .ant-dropdown-menu, .ant-menu-item,
.ant-input, .ant-select-selector, .ant-btn {
