    background-color var(--md-sys-motion-duration-medium1) var(--md-sys-motion-easing-standard),
    border-color var(--md-sys-motion-duration-short4) var(--md-sys-motion-easing-standard),
    color var(--md-sys-motion-duration-short4) var(--md-sys-motion-easing-standard),
    box-shadow var(--md-sys-motion-duration-short4) var(--md-sys-motion-easing-standard);
}

/* ==================== M3 Typography ==================== */

h1, h2, h3, h4, h5, h6,
.ant-typography h1, .ant-typography h2, .ant-typography h3, .ant-typography h4 {
  font-weight: 400;
  letter-spacing: 0;
}

/* M3 排版层级 */
.wc-display { font-size: var(--md-sys-typescale-display-small); font-weight: 400; line-height: 1.2; }
.wc-title   { font-size: var(--md-sys-typescale-headline-small); font-weight: 400; line-height: 1.3; }
.wc-h1 { font-size: var(--md-sys-typescale-headline-large); font-weight: 400; color: var(--md-sys-color-on-surface); }
.wc-h2 { font-size: var(--md-sys-typescale-headline-medium); font-weight: 400; color: var(--md-sys-color-on-surface); }
.wc-h3 { font-size: var(--md-sys-typescale-title-large); font-weight: 400; color: var(--md-sys-color-on-surface); }
.wc-h4 { font-size: var(--md-sys-typescale-title-medium); font-weight: 500; color: var(--md-sys-color-on-surface); }

.wc-body-lg { font-size: var(--md-sys-typescale-body-large); color: var(--md-sys-color-on-surface-variant); }
.wc-body    { font-size: var(--md-sys-typescale-body-medium); color: var(--md-sys-color-on-surface-variant); }
.wc-body-sm { font-size: var(--md-sys-typescale-body-small); color: var(--md-sys-color-on-surface-variant); }
.wc-caption { font-size: var(--md-sys-typescale-label-small); color: var(--md-sys-color-on-surface-variant); }
.wc-label   { font-size: var(--md-sys-typescale-label-medium); color: var(--md-sys-color-on-surface-variant); font-weight: 500; letter-spacing: 0.5px; }

/* ==================== M3 Form ==================== */

.ant-form-item-label > label {
  font-size: var(--md-sys-typescale-body-small) !important;
  font-weight: 400 !important;
  color: var(--md-sys-color-on-surface-variant) !important;
}

.ant-form-item-required::before {
  color: var(--md-sys-color-error) !important;
}

.ant-form-item-explain-error {
  font-size: var(--md-sys-typescale-body-small) !important;
  color: var(--md-sys-color-error) !important;
}

/* ==================== M3 Select ==================== */

.ant-select-item-option-selected {
  background: var(--md-sys-color-secondary-container) !important;
  color: var(--md-sys-color-on-secondary-container) !important;
  font-weight: 500 !important;
}

.ant-select-item-option-active {
  background: rgba(27, 27, 31, 0.08) !important;
}

.ant-select-dropdown {
  border-radius: var(--md-sys-shape-extra-small) !important;
  box-shadow: var(--md-sys-elevation-2) !important;
  background: var(--md-sys-color-surface-container) !important;
}

/* ==================== M3 Drawer ==================== */

.ant-drawer-content {
  border-radius: var(--md-sys-shape-large) 0 0 var(--md-sys-shape-large) !important;
  background: var(--md-sys-color-surface-container-low) !important;
}

.ant-drawer-header {
  border-bottom: 1px solid var(--md-sys-color-outline-variant) !important;
  padding: 24px !important;
}

.ant-drawer-title {
  font-size: var(--md-sys-typescale-title-large) !important;
  font-weight: 400 !important;
  color: var(--md-sys-color-on-surface) !important;
}

/* ==================== M3 Notification / Message ==================== */

.ant-message-notice-content {
  border-radius: var(--md-sys-shape-extra-small) !important;
  background: var(--md-sys-color-inverse-surface) !important;
  color: var(--md-sys-color-inverse-on-surface) !important;
  box-shadow: var(--md-sys-elevation-3) !important;
  padding: 12px 16px !important;
}

.ant-notification-notice {
  border-radius: var(--md-sys-shape-medium) !important;
