  border-radius: var(--md-sys-shape-medium) !important;
}

.ant-alert-error {
  background: var(--md-sys-color-error-container) !important;
  border: none !important;
  border-radius: var(--md-sys-shape-medium) !important;
  color: var(--md-sys-color-on-error-container) !important;
}

/* ==================== M3 Spin ==================== */

.ant-spin-dot-item {
