}

.auth-card,
.login-card,
.register-card {
  background: var(--md-sys-color-surface-container-low) !important;
  border-radius: var(--md-sys-shape-extra-large) !important;
  box-shadow: var(--md-sys-elevation-2) !important;
  border: none !important;
}

/* ==================== 状态标签 ==================== */

.status-tag {
  display: inline-flex;
  align-items: center;
  padding: 4px 12px;
  border-radius: var(--md-sys-shape-small);
  font-size: var(--md-sys-typescale-label-medium);
  font-weight: 500;
  line-height: 20px;
  white-space: nowrap;
}

.status-draft      { color: var(--status-draft-fg);     background: var(--status-draft-bg); }
.status-matching   { color: var(--status-matching-fg);  background: var(--status-matching-bg); }
